 28→        visitorModifiers = setOf(
 29→            VisitorModifier.RunAfterRule(
 30→                // This rule should run after all other rules. Each time a rule visitor is modified with
 31→                // RunAsLateAsPossible, it needs to be checked that this rule still runs after that new rule or that it
 32→                // won't be affected by that rule.
 33→                ruleId = TRAILING_COMMA_ON_CALL_SITE_RULE_ID,
 34→                mode = REGARDLESS_WHETHER_RUN_AFTER_RULE_IS_LOADED_OR_DISABLED,
 35→            ),
 36→            VisitorModifier.RunAfterRule(
 37→                // This rule should run after all other rules. Each time a rule visitor is modified with
 38→                // RunAsLateAsPossible, it needs to be checked that this rule still runs after that new rule or that it
 39→                // won't be affected by that rule.
 40→                ruleId = TRAILING_COMMA_ON_DECLARATION_SITE_RULE_ID,
 41→                mode = REGARDLESS_WHETHER_RUN_AFTER_RULE_IS_LOADED_OR_DISABLED,
 42→            ),
 43→            VisitorModifier.RunAsLateAsPossible,
 44→        ),
 45→        usesEditorConfigProperties = setOf(
 46→            MAX_LINE_LENGTH_PROPERTY,
 47→            IGNORE_BACKTICKED_IDENTIFIER_PROPERTY,
 48→        ),
 49→    ) {
