class FunctionReturnTypeSpacingRuleMaxLineLengthTest {
    private val functionReturnTypeSpacingRuleAssertThat = assertThatRule { FunctionReturnTypeSpacingRule() }

    @Test
    fun `Given a newline between the colon and the return type to prevent exceeding max line length then do not reformat`() {
        val code =
            """
            fun ${"a".repeat(60)}():
                ReturnType {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 70)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a newline between the closing parenthesis and the colon of the return type to prevent exceeding max line length then do not reformat`() {
        val code =
            """
            fun ${"a".repeat(60)}()
                : ReturnType {
            }
            """.trimIndent()
        functionReturnTypeSpacingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 70)
            .hasNoLintViolations()
    }
